import{_ as n,o as a,c as e,a0 as i}from"./chunks/framework.DTwdCQre.js";const h=JSON.parse('{"title":"Tutorial 3: Understanding the Agent Loop","description":"","frontmatter":{},"headers":[],"relativePath":"guide/tutorials/03-agent-loop.md","filePath":"guide/tutorials/03-agent-loop.md","lastUpdated":1775554522000}'),t={name:"guide/tutorials/03-agent-loop.md"};function p(l,s,o,r,c,u){return a(),e("div",null,[...s[0]||(s[0]=[i(`<h1 id="tutorial-3-understanding-the-agent-loop" tabindex="-1">Tutorial 3: Understanding the Agent Loop <a class="header-anchor" href="#tutorial-3-understanding-the-agent-loop" aria-label="Permalink to &quot;Tutorial 3: Understanding the Agent Loop&quot;">​</a></h1><p>Deep dive into how claude-code-Go&#39;s agent loop works.</p><h2 id="what-is-the-agent-loop" tabindex="-1">What is the Agent Loop? <a class="header-anchor" href="#what-is-the-agent-loop" aria-label="Permalink to &quot;What is the Agent Loop?&quot;">​</a></h2><p>The agent loop is the core decision-making engine. It&#39;s a continuous cycle where the AI:</p><ol><li><strong>Thinks</strong> about what to do</li><li><strong>Acts</strong> by calling tools</li><li><strong>Observes</strong> the results</li><li><strong>Repeats</strong> until done</li></ol><p>This is inspired by the ReAct (Reasoning + Acting) pattern from AI research.</p><h2 id="the-loop-states" tabindex="-1">The Loop States <a class="header-anchor" href="#the-loop-states" aria-label="Permalink to &quot;The Loop States&quot;">​</a></h2><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────┐     ┌──────────┐     ┌────────────┐</span></span>
<span class="line"><span>│   User      │────▶│  Think   │────▶│   Act      │</span></span>
<span class="line"><span>│   Input     │     │          │     │  (Tool)    │</span></span>
<span class="line"><span>└─────────────┘     └──────────┘     └────────────┘</span></span>
<span class="line"><span>                                             │</span></span>
<span class="line"><span>                                             ▼</span></span>
<span class="line"><span>┌─────────────┐     ┌──────────┐     ┌────────────┐</span></span>
<span class="line"><span>│   Respond   │◀────│  Think   │◀────│  Observe   │</span></span>
<span class="line"><span>│   to User   │     │  Again   │     │  (Result)  │</span></span>
<span class="line"><span>└─────────────┘     └──────────┘     └────────────┘</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br></div></div><h2 id="state-breakdown" tabindex="-1">State Breakdown <a class="header-anchor" href="#state-breakdown" aria-label="Permalink to &quot;State Breakdown&quot;">​</a></h2><h3 id="_1-user-input" tabindex="-1">1. User Input <a class="header-anchor" href="#_1-user-input" aria-label="Permalink to &quot;1. User Input&quot;">​</a></h3><p>You type a message. This could be:</p><ul><li>A question: &quot;What does this code do?&quot;</li><li>A command: &quot;Refactor this function&quot;</li><li>A conversation: &quot;Let&#39;s plan the architecture&quot;</li></ul><h3 id="_2-think" tabindex="-1">2. Think <a class="header-anchor" href="#_2-think" aria-label="Permalink to &quot;2. Think&quot;">​</a></h3><p>The AI processes your input and decides what to do:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>User: &quot;Read main.go and explain it&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>AI thinks:</span></span>
<span class="line"><span>- The user wants me to read a file</span></span>
<span class="line"><span>- I should use the Read tool</span></span>
<span class="line"><span>- File path is &quot;main.go&quot;</span></span>
<span class="line"><span>- After reading, I&#39;ll need to explain the content</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><h3 id="_3-act" tabindex="-1">3. Act <a class="header-anchor" href="#_3-act" aria-label="Permalink to &quot;3. Act&quot;">​</a></h3><p>The AI calls one or more tools:</p><div class="language-json vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;tool&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Read&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;arguments&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;file_path&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;main.go&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><h3 id="_4-observe" tabindex="-1">4. Observe <a class="header-anchor" href="#_4-observe" aria-label="Permalink to &quot;4. Observe&quot;">​</a></h3><p>The tool executes and returns results:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Result: package main</span></span>
<span class="line"><span></span></span>
<span class="line"><span>import &quot;fmt&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>func main() {</span></span>
<span class="line"><span>    fmt.Println(&quot;Hello&quot;)</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><h3 id="_5-think-again" tabindex="-1">5. Think Again <a class="header-anchor" href="#_5-think-again" aria-label="Permalink to &quot;5. Think Again&quot;">​</a></h3><p>The AI processes the result:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>AI thinks:</span></span>
<span class="line"><span>- I&#39;ve successfully read the file</span></span>
<span class="line"><span>- It&#39;s a simple Go program</span></span>
<span class="line"><span>- It prints &quot;Hello&quot;</span></span>
<span class="line"><span>- I should explain this to the user</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><h3 id="_6-respond" tabindex="-1">6. Respond <a class="header-anchor" href="#_6-respond" aria-label="Permalink to &quot;6. Respond&quot;">​</a></h3><p>The AI generates a response:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>This is a simple Go program that:</span></span>
<span class="line"><span>1. Declares itself as package &quot;main&quot;</span></span>
<span class="line"><span>2. Imports the &quot;fmt&quot; package for formatting</span></span>
<span class="line"><span>3. Has a main() function that prints &quot;Hello&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>When run, it will output: Hello</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><h2 id="stop-reasons" tabindex="-1">Stop Reasons <a class="header-anchor" href="#stop-reasons" aria-label="Permalink to &quot;Stop Reasons&quot;">​</a></h2><p>The loop continues until one of these conditions:</p><table tabindex="0"><thead><tr><th>Stop Reason</th><th>Meaning</th><th>Example</th></tr></thead><tbody><tr><td><code>end_turn</code></td><td>AI is done responding</td><td>After explaining code</td></tr><tr><td><code>tool_use</code></td><td>AI wants to use a tool</td><td>&quot;Let me read that file&quot;</td></tr><tr><td><code>max_tokens</code></td><td>Context limit reached</td><td>Long conversation</td></tr><tr><td><code>stop_sequence</code></td><td>Special stop token</td><td>End of generation</td></tr></tbody></table><h2 id="multi-turn-example" tabindex="-1">Multi-Turn Example <a class="header-anchor" href="#multi-turn-example" aria-label="Permalink to &quot;Multi-Turn Example&quot;">​</a></h2><p>Complex tasks require multiple loop iterations:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>User: &quot;Find all TODO comments and create a task list&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Loop 1:</span></span>
<span class="line"><span>  Think: &quot;I need to search for TODO comments&quot;</span></span>
<span class="line"><span>  Act: Grep {&quot;pattern&quot;: &quot;TODO&quot;, &quot;path&quot;: &quot;.&quot;}</span></span>
<span class="line"><span>  Observe: Found 3 TODOs in 2 files</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Loop 2:</span></span>
<span class="line"><span>  Think: &quot;I found TODOs, now I need to read them&quot;</span></span>
<span class="line"><span>  Act: Read {&quot;file_path&quot;: &quot;main.go&quot;}</span></span>
<span class="line"><span>  Observe: &quot;// TODO: Add error handling&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Loop 3:</span></span>
<span class="line"><span>  Think: &quot;I have the details, now create the task list&quot;</span></span>
<span class="line"><span>  Act: TodoWrite {&quot;todos&quot;: [&quot;Add error handling in main.go&quot;]}</span></span>
<span class="line"><span>  Observe: Task list created</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Loop 4:</span></span>
<span class="line"><span>  Think: &quot;All tasks complete, respond to user&quot;</span></span>
<span class="line"><span>  Respond: &quot;Created a task list with 1 item...&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br></div></div><h2 id="loop-limits" tabindex="-1">Loop Limits <a class="header-anchor" href="#loop-limits" aria-label="Permalink to &quot;Loop Limits&quot;">​</a></h2><p>To prevent infinite loops:</p><ul><li><strong>Max turns</strong>: 10 iterations per user message (configurable)</li><li><strong>Timeout</strong>: 30 seconds per tool execution</li><li><strong>Token limit</strong>: Automatic context compaction when approaching limits</li></ul><p>You can adjust these in settings:</p><div class="language-json vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;maxTurns&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">20</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;timeout&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;60s&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><h2 id="visualizing-the-loop" tabindex="-1">Visualizing the Loop <a class="header-anchor" href="#visualizing-the-loop" aria-label="Permalink to &quot;Visualizing the Loop&quot;">​</a></h2><p>Enable debug mode to see the loop in action:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&gt; /debug on</span></span>
<span class="line"><span></span></span>
<span class="line"><span># Now you&#39;ll see each state transition:</span></span>
<span class="line"><span>[THINK] Analyzing user request...</span></span>
<span class="line"><span>[ACT] Calling tool: Read</span></span>
<span class="line"><span>[OBSERVE] Tool returned 150 lines</span></span>
<span class="line"><span>[THINK] Summarizing content...</span></span>
<span class="line"><span>[RESPOND] Generating response...</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><h2 id="exercise-trace-the-loop" tabindex="-1">Exercise: Trace the Loop <a class="header-anchor" href="#exercise-trace-the-loop" aria-label="Permalink to &quot;Exercise: Trace the Loop&quot;">​</a></h2><p>For this request, trace through each state:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&gt; Find all functions in main.go and count them</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><details><summary>Click to see the answer</summary><p><strong>Loop 1:</strong></p><ul><li>Think: User wants to find functions in main.go</li><li>Act: Read main.go</li><li>Observe: File content returned</li></ul><p><strong>Loop 2:</strong></p><ul><li>Think: I have the file content, need to count functions</li><li>Act: No tool needed, I can analyze directly</li><li>Respond: &quot;Found 3 functions: main(), init(), helper()&quot;</li></ul></details><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><ul><li><a href="./04-permission-system.html">Tutorial 4: Permission System</a> - Learn about security</li><li><a href="./../../architecture/agent-loop-state-machine.html">Architecture Deep Dive</a> - Technical details</li><li><a href="./../../adr/001-agent-loop.html">ADR-001: Agent Loop Design</a> - Design decisions</li></ul>`,47)])])}const b=n(t,[["render",p]]);export{h as __pageData,b as default};
